<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('sales.view');$status=vp3_input('status');$sql='SELECT p.*,l.name lead_name,c.name customer_name,a.name admin_name,(SELECT COUNT(*) FROM proposal_items pi WHERE pi.proposal_id=p.id) item_count FROM proposals p LEFT JOIN leads l ON l.id=p.lead_id LEFT JOIN customers c ON c.id=p.customer_id JOIN admins a ON a.id=p.created_by_admin_id WHERE 1=1';$params=[];if($status!==''){$sql.=' AND p.status=?';$params[]=$status;}$sql.=' ORDER BY p.created_at DESC LIMIT 250';$rows=[];try{$stmt=vp3_db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();}catch(Throwable){}$pageTitle='Proposals';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Scope and close</span><h1>Proposals</h1><p>Create clear scopes, package combinations, deposits, terms, and customer acceptance records.</p></div><a class="button" href="proposal.php">Create proposal</a></div><form class="admin-filter"><label>Status<select name="status"><option value="">All</option><?php foreach(['draft','sent','viewed','accepted','declined','expired','cancelled'] as $v):?><option <?=$status===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><button class="button small">Filter</button></form><div class="table-wrap"><table class="table"><thead><tr><th>Proposal</th><th>Lead / customer</th><th>Items</th><th>Total</th><th>Status</th><th>Valid until</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><a href="proposal.php?id=<?=(int)$r['id']?>"><strong><?=vp3_e($r['proposal_number'])?></strong></a><br><small><?=vp3_e($r['title'])?></small></td><td><?=vp3_e($r['customer_name']?:$r['lead_name']?:'—')?></td><td><?=(int)$r['item_count']?></td><td><?=vp3_e(vp3_money((int)$r['total_cents'],$r['currency']))?></td><td><span class="badge <?=vp3_e($r['status'])?>"><?=vp3_e($r['status'])?></span></td><td><?=vp3_e($r['valid_until']?:'—')?></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="6">No proposals.</td></tr><?php endif;?></tbody></table></div>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
